;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@question title="<y>Will you drink water from the gushing spring?" cancel=true
[if exp='tf.result']
	@eval exp='o.噴水.doDamage = o.マジックバリア.doDamage'
	@eval exp='o.噴水.resultMessage = o.マジックバリア.resultMessage'
	@btcmd name=噴水
	@notice text="The magic resistance of the party was temporarily increased!"
[endif]

[eventoff]
